import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as i}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as l,o as n,c as o,a2 as t}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Safety/cloudflare-api-token.md","filePath":"vi-VN/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),h={name:"vi-VN/Safety/cloudflare-api-token.md"};function c(r,e,d,s,u,p){return n(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API credentials cho phép ImgBed purge Cloudflare CDN cache sau khi files thay đổi.</p><p><img src="'+a+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="cau-hinh-o-đau" tabindex="-1">Cấu hình ở đâu <a class="header-anchor" href="#cau-hinh-o-đau" aria-label="Permalink to &quot;Cấu hình ở đâu&quot;">​</a></h2><p>Mở admin panel, rồi vào:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>Bạn cần điền:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="setting-nay-lam-gi" tabindex="-1">Setting này làm gì <a class="header-anchor" href="#setting-nay-lam-gi" aria-label="Permalink to &quot;Setting này làm gì&quot;">​</a></h2><p>Cloudflare có thể cache public image URLs.</p><p>Caching giúp image tải nhanh hơn, nhưng cũng có thể khiến content cũ vẫn hiển thị một thời gian sau khi bạn delete, block, replace hoặc move file.</p><p>Sau khi Cloudflare API credentials được cấu hình, ImgBed sẽ cố purge Cloudflare cache liên quan khi các thao tác đó hoàn tất.</p><p>Hữu ích khi:</p><ul><li>Bạn delete image và muốn public link ngừng hoạt động càng sớm càng tốt.</li><li>Bạn block image và không muốn visitors thấy original file.</li><li>Bạn replace file cùng tên và muốn visitors thấy version mới nhanh hơn.</li><li>Bạn move hoặc rename files và muốn old path cache refresh nhanh.</li><li>Bạn đổi public access rules và muốn public gallery hoặc random image cache update nhanh hơn.</li></ul><h2 id="neu-đe-trong-thi-sao" tabindex="-1">Nếu để trống thì sao <a class="header-anchor" href="#neu-đe-trong-thi-sao" aria-label="Permalink to &quot;Nếu để trống thì sao&quot;">​</a></h2><p>ImgBed vẫn hoạt động bình thường nếu không cấu hình setting này.</p><p>Khác biệt duy nhất là ImgBed sẽ không actively purge Cloudflare CDN cache. Visitors có thể tiếp tục thấy content cũ cho đến khi Cloudflare cache tự expire.</p><h2 id="cach-tim-zone-id" tabindex="-1">Cách tìm Zone ID <a class="header-anchor" href="#cach-tim-zone-id" aria-label="Permalink to &quot;Cách tìm Zone ID&quot;">​</a></h2><p>Zone ID là Cloudflare Zone ID của site đang dùng cho ImgBed domain.</p><ol><li>Sign in vào Cloudflare dashboard.</li><li>Mở site chứa ImgBed domain.</li><li>Tìm <code>Zone ID</code> trên site overview page.</li><li>Copy vào field <code>Zone ID</code> trong ImgBed.</li></ol><p>Đây là site Zone ID, không phải account ID.</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>Nhập email address bạn dùng để sign in vào Cloudflare.</p><p>Email này phải khớp với API Key bên dưới.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Nhập Cloudflare Global API Key.</p><ol><li>Sign in vào Cloudflare dashboard.</li><li>Mở profile.</li><li>Vào API Tokens page.</li><li>Tìm <code>Global API Key</code>.</li><li>View và copy.</li><li>Paste vào field <code>API Key</code> trong ImgBed.</li></ol><p><img src="'+i+'" alt="View global API key" loading="lazy"></p><h2 id="khi-nao-co-hieu-luc" tabindex="-1">Khi nào có hiệu lực <a class="header-anchor" href="#khi-nao-co-hieu-luc" aria-label="Permalink to &quot;Khi nào có hiệu lực&quot;">​</a></h2><p>Sau khi điền fields, save settings.</p><p>Các file changes sau đó sẽ tự động cố purge Cloudflare cache. Past operations không được purge ngược lại. Nếu đã delete hoặc replace file trước khi thiết lập, hãy chờ Cloudflare cache expire hoặc purge thủ công trong Cloudflare.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="co-bat-buoc-khong" tabindex="-1">Có bắt buộc không? <a class="header-anchor" href="#co-bat-buoc-khong" aria-label="Permalink to &quot;Có bắt buộc không?&quot;">​</a></h3><p>Không.</p><p>Nếu domain không dùng Cloudflare, hoặc bạn không ngại CDN cache delay, có thể để trống.</p><h3 id="credentials-sai-co-lam-hong-uploads-khong" tabindex="-1">Credentials sai có làm hỏng Uploads không? <a class="header-anchor" href="#credentials-sai-co-lam-hong-uploads-khong" aria-label="Permalink to &quot;Credentials sai có làm hỏng Uploads không?&quot;">​</a></h3><p>Thường là không.</p><p>Credentials sai chỉ khiến ImgBed không purge được Cloudflare cache. Upload và normal file access vẫn nên hoạt động.</p><h3 id="vi-sao-deleted-image-van-mo-đuoc" tabindex="-1">Vì sao Deleted Image vẫn mở được? <a class="header-anchor" href="#vi-sao-deleted-image-van-mo-đuoc" aria-label="Permalink to &quot;Vì sao Deleted Image vẫn mở được?&quot;">​</a></h3><p>Nguyên nhân phổ biến nhất là Cloudflare vẫn cache file cũ.</p><p>Khi Cloudflare API credentials đúng, ImgBed sẽ purge related URL cache khi file bị delete.</p><h3 id="vi-sao-replace-file-roi-van-thay-image-cu" tabindex="-1">Vì sao Replace File rồi vẫn thấy Image cũ? <a class="header-anchor" href="#vi-sao-replace-file-roi-van-thay-image-cu" aria-label="Permalink to &quot;Vì sao Replace File rồi vẫn thấy Image cũ?&quot;">​</a></h3><p>Điều này cũng thường do CDN cache.</p><p>Sau khi setting này được cấu hình, ImgBed sẽ cố purge old URL cache khi file cùng tên bị overwrite.</p>',44)])])}const b=l(h,[["render",c]]);export{k as __pageData,b as default};
